    {
      "base_method": "nested dropout",
      "variant_tag": "nested dropout:naive",
      "description": "训练时随机截断尾token，仅用前k个token重建，导致信息集中在早token、尾token利用率低。"
    },
    {
      "base_method": "nested dropout",
      "variant_tag": "nested dropout:redundant-token-padding",
      "description": "在原序列尾部追加M个padding query/token，把dropout截断作用“推后”，从而更频繁激活原始尾token；下游生成时丢弃padding token仅保留原N=256。"
    },
    {
      "base_method": "representation alignment",
      "variant_tag": "representation alignment:hierarchical-decay",
      "description": "将decoder中间特征与DINOv2特征做cosine对齐，但令权重λ(k)随保留长度k线性衰减：短序列强语义、长序列弱约束以补细节。"
    },
    {
      "base_method": "decoder finetuning",
      "variant_tag": "decoder finetuning:relaxed-semreg",
      "description": "冻结encoder与quantizer，仅微调decoder并把λ(k)设为较小常数，提升短token(32/64)重建与对应生成质量。"
    },
    {
      "base_method": "gigatok",
      "variant_tag": "gigatok:flexible-retok",
      "description": "沿用GigaTok的1D ViT encoder-decoder+quantizer架构与训练损失，在其上加入padding+分层语义正则并进行decoder微调，得到可变长度版本。"
    }
  ],
